code.C:
#include <stdio.h>
int main(){
    const float celsius = 20.5f;
    float fahrenheit = (celsius * 9.0f / 5.0f) + 32.0f;
    printf("%.6f\n", fahrenheit);
    return 0;
}

code.C++:
#include <bits/stdc++.h>
using namespace std;
int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    const double celsius = 20.5;
    double fahrenheit = (celsius * 9.0 / 5.0) + 32.0;
    cout.setf(ios::fixed);
    cout<<setprecision(6)<<fahrenheit<<"\n";
    return 0;
}

